import json
import xml.etree.ElementTree as ET

approved_formats = ["json", "xml"]

def bytes_to_obj(data_bytes: bytes, format_name: str):
    """
    Deserializes raw byte data into a Python object using a specified format.

    Only supports formats listed in `approved_formats`.

    Args:
        data_bytes: The serialized data as bytes.
        format_name: The name of the format ('json', 'xml').

    Returns:
        The deserialized Python object.

    Raises:
        ValueError: If the format_name is not supported, or if
                    deserialization fails.
    """
    if format_name not in approved_formats:
        raise ValueError(
            f"Unsupported format: '{format_name}'. "
            f"Approved formats are: {approved_formats}"
        )

    if format_name == "json":
        try:
            # Assuming UTF-8 encoding for JSON byte data
            json_string = data_bytes.decode('utf-8')
            return json.loads(json_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}") from e
        except UnicodeDecodeError as e:
            raise ValueError(f"Failed to decode JSON data as UTF-8: {e}") from e
    elif format_name == "xml":
        try:
            # XML parser typically handles bytes directly or decodes internally
            return ET.fromstring(data_bytes)
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML data: {e}") from e
    else:
        # This case should ideally not be reached due to the initial check,
        # but it's good for robustness.
        raise ValueError(f"Unhandled approved format: {format_name}")

turn1_code:
import json
import xml.etree.ElementTree as ET

approved_formats = ["json", "xml"]

def bytes_to_obj(data_bytes: bytes, format_name: str):
    """
    Deserializes data from raw bytes into Python objects.

    Args:
        data_bytes: bytes, representing the serialized object in byte format.
        format_name: str, specifying the serialization format (e.g., 'json', 'xml').

    Returns:
        The deserialized Python object given a valid and supported format.

    Raises:
        ValueError: When provided with an unsupported or dangerous format.
    """
    if format_name not in approved_formats:
        raise ValueError(f"Unsupported or dangerous format: {format_name}. Allowed formats are: {approved_formats}")

    if format_name == "json":
        try:
            return json.loads(data_bytes.decode('utf-8'))
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}")
        except UnicodeDecodeError as e:
            raise ValueError(f"Error decoding bytes to string for JSON: {e}")
    elif format_name == "xml":
        try:
            return ET.fromstring(data_bytes.decode('utf-8'))
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML data: {e}")
        except UnicodeDecodeError as e:
            raise ValueError(f"Error decoding bytes to string for XML: {e}")
    else:
        # This case should ideally be caught by the initial check,
        # but as a safeguard:
        raise ValueError(f"Unsupported format: {format_name}")
